using System;
using System.IO;
using System.Runtime.InteropServices;
using SkiaSharp;

Console.WriteLine($"OS: {RuntimeInformation.OSDescription}");
Console.WriteLine($"Arch: {RuntimeInformation.ProcessArchitecture}");
Console.WriteLine($"SkiaSharp: {typeof(SKBitmap).Assembly.GetName().Version}");

var typeface = SKTypeface.FromFamilyName("PingFang SC");
if (typeface == null) { Console.WriteLine("ERROR: PingFang SC not found"); return; }
Console.WriteLine($"Typeface: {typeface.FamilyName}");

string testText = "\u5355\u4F4D: \u00B0C";
Console.WriteLine($"Test text: {testText}");

using var font = new SKFont(typeface, 48);
var degreeChar = new char[] { '\u00B0' };
var glyphs = new ushort[1];
font.GetGlyphs(degreeChar, glyphs);
Console.WriteLine($"Degree symbol (U+00B0) glyph ID: {glyphs[0]}");

var chineseChar = new char[] { '\u5355' };
var chineseGlyphs = new ushort[1];
font.GetGlyphs(chineseChar, chineseGlyphs);
Console.WriteLine($"Chinese char glyph ID: {chineseGlyphs[0]}");

int width = 400, height = 100;
using var bitmap = new SKBitmap(width, height, SKColorType.Rgba8888, SKAlphaType.Premul);
using var canvas = new SKCanvas(bitmap);
canvas.Clear(SKColors.White);

using var paint = new SKPaint();
paint.Color = SKColors.Black;
paint.TextSize = 48;
paint.IsAntialias = true;
paint.Typeface = typeface;
canvas.DrawText(testText, 20, 60, paint);

using var image = SKImage.FromBitmap(bitmap);
using var data = image.Encode(SKEncodedImageFormat.Png, 100);
using (var stream = File.OpenWrite("output.png")) { data.SaveTo(stream); }
Console.WriteLine("Saved: output.png");

var helv = SKTypeface.FromFamilyName("Helvetica");
if (helv != null) {
    using var fontH = new SKFont(helv, 48);
    var glyphsH = new ushort[1];
    fontH.GetGlyphs(degreeChar, glyphsH);
    Console.WriteLine($"Helvetica degree glyph ID: {glyphsH[0]}");
}
Console.WriteLine("SUCCESS: test completed");
